"""
Output file writers for vendoring.
"""

from __future__ import annotations

import subprocess
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from pathlib import Path


def write_vendor_init(vendor_dir: Path) -> Path:
    """
    Create an __init__.py for the vendor directory.
    """
    vendor_dir.mkdir(parents=True, exist_ok=True)
    init_file = vendor_dir / "__init__.py"
    init_file.write_text(
        '''"""
Vendored pheno-sdk packages for production deployment.

This directory contains copies of pheno-sdk packages to avoid
dependency on relative paths in production environments.
"""

__version__ = "1.0.0"
''',
    )
    return init_file


def generate_prod_requirements(project_root: Path, output_file: Path | None = None) -> Path:
    """
    Write requirements-prod.txt without editable pheno-sdk references.
    """
    output_file = output_file or project_root / "requirements-prod.txt"
    requirements_path = project_root / "requirements.txt"
    if not requirements_path.exists():
        raise FileNotFoundError(f"requirements.txt not found at {requirements_path}")

    lines = requirements_path.read_text().splitlines()

    prod_lines = [
        "# " + "=" * 76,
        "# Production Requirements",
        "# " + "=" * 76,
        "# This file uses VENDORED pheno-sdk packages from pheno_vendor/",
        "# For development, use requirements.txt with editable installs",
        "# Generated by pheno-vendor",
        "# " + "=" * 76,
        "",
    ]

    for line in lines:
        stripped = line.strip()
        if stripped.startswith("-e") and "pheno-sdk" in stripped:
            continue
        if "PHENO-SDK" in stripped.upper():
            continue
        prod_lines.append(line)

    output_file.write_text("\n".join(prod_lines))
    return output_file


def create_sitecustomize(project_root: Path, vendor_dir_name: str = "pheno_vendor") -> Path:
    """
    Ensure sitecustomize.py points to the vendor directory.
    """
    sitecustomize = project_root / "sitecustomize.py"
    sitecustomize.write_text(
        f'''"""
Site customization to add vendored pheno-sdk packages to sys.path.

This file is automatically loaded by Python at startup and ensures
vendored packages in {vendor_dir_name}/ are available for import.
"""

import sys
from pathlib import Path

# Add {vendor_dir_name} to path if it exists
vendor_path = Path(__file__).parent / "{vendor_dir_name}"
if vendor_path.exists() and str(vendor_path) not in sys.path:
    sys.path.insert(0, str(vendor_path))
''',
    )
    return sitecustomize


def generate_manifest(vendor_dir: Path, pheno_sdk_root: Path) -> Path:
    """
    Create a manifest describing vendored packages.
    """
    manifest_path = vendor_dir / "VENDOR_MANIFEST.txt"
    manifest_lines = ["Pheno-SDK Vendored Packages Manifest"]

    try:
        generated = subprocess.check_output(["date"]).decode().strip()
    except Exception:
        generated = "unknown"

    manifest_lines.append(f"Generated: {generated}")
    manifest_lines.append(f"Source: {pheno_sdk_root}")
    manifest_lines.append("")
    manifest_lines.append("Packages:")

    for pkg_dir in sorted(vendor_dir.iterdir()):
        if not pkg_dir.is_dir() or pkg_dir.name.startswith("_"):
            continue

        files = list(pkg_dir.rglob("*"))
        py_files = [file for file in files if file.suffix == ".py"]
        size_bytes = sum(file.stat().st_size for file in files if file.is_file())
        size_mb = size_bytes / (1024 * 1024)
        manifest_lines.append(f"  - {pkg_dir.name} ({len(py_files)} .py files, {size_mb:.2f} MB)")

    total_size = sum(file.stat().st_size for file in vendor_dir.rglob("*") if file.is_file())
    total_mb = total_size / (1024 * 1024)
    manifest_lines.append("")
    manifest_lines.append(f"Total size: {total_mb:.2f} MB")

    manifest_path.write_text("\n".join(manifest_lines))
    return manifest_path


__all__ = [
    "create_sitecustomize",
    "generate_manifest",
    "generate_prod_requirements",
    "write_vendor_init",
]
